import React, { useState } from "react";

function App() {
  const maxPlayers = 7;
  const availableColors = [
    "violet",
    "darkblue",
    "lightblue",
    "yellow",
    "orange",
    "red",
    "green",
  ];

  const [players, setPlayers] = useState([]);
  const [newPlayerName, setNewPlayerName] = useState("");
  const [newPlayerColor, setNewPlayerColor] = useState("");
  const [gameStarted, setGameStarted] = useState(false);

  const addPlayer = () => {
    if (!newPlayerName || !newPlayerColor) return;

    if (players.some((p) => p.color === newPlayerColor)) {
      alert("Color already taken! Choose another.");
      return;
    }

    setPlayers([
      ...players,
      {
        name: newPlayerName,
        color: newPlayerColor,
        position: 0,
        zchutPoints: 0,
        money: 0,
      },
    ]);

    setNewPlayerName("");
    setNewPlayerColor("");
  };

  const startGame = () => {
    if (players.length < 2) {
      alert("At least 2 players required to start the game.");
      return;
    }
    setGameStarted(true);
  };

  return (
    <div style={styles.container}>
      <h1>TorahPoly: Player Setup</h1>

      {!gameStarted ? (
        <>
          {players.length < maxPlayers && (
            <div style={styles.inputRow}>
              <input
                type="text"
                placeholder="Player Name"
                value={newPlayerName}
                onChange={(e) => setNewPlayerName(e.target.value)}
                style={styles.input}
              />
              <select
                value={newPlayerColor}
                onChange={(e) => setNewPlayerColor(e.target.value)}
                style={styles.input}
              >
                <option value="">Choose Color</option>
                {availableColors
                  .filter((c) => !players.some((p) => p.color === c))
                  .map((color) => (
                    <option key={color} value={color}>
                      {color}
                    </option>
                  ))}
              </select>
              <button onClick={addPlayer} style={styles.button}>
                Add Player
              </button>
            </div>
          )}

          <h2>Joined Players ({players.length}/{maxPlayers})</h2>
          <ul>
            {players.map((p, index) => (
              <li key={index} style={{ color: p.color, fontWeight: "bold" }}>
                {p.name} ({p.color})
              </li>
            ))}
          </ul>

          <button onClick={startGame} style={{ ...styles.button, marginTop: 20 }}>
            Start Game
          </button>
        </>
      ) : (
        <div>
          <h2>Game Started!</h2>
          <p>All players are in starting positions.</p>
          <ul>
            {players.map((p, index) => (
              <li key={index} style={{ color: p.color, fontWeight: "bold" }}>
                {p.name} - Position: {p.position}, Zchut: {p.zchutPoints}, Money: ${p.money}
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}

const styles = {
  container: {
    fontFamily: "Arial, sans-serif",
    padding: 20,
    backgroundColor: "#f0f2f5",
    minHeight: "100vh",
    textAlign: "center",
  },
  inputRow: {
    display: "flex",
    justifyContent: "center",
    gap: 10,
    marginBottom: 20,
  },
  input: {
    padding: "6px 12px",
    fontSize: 16,
    borderRadius: 4,
    border: "1px solid #ccc",
  },
  button: {
    padding: "8px 16px",
    fontSize: 16,
    borderRadius: 6,
    border: "none",
    cursor: "pointer",
    backgroundColor: "#007bff",
    color: "white",
  },
};

export default App;
